logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

def lambda_handler(event, context):
    try:
        # Get the bucket and object key from the event
        bucket = event['Records'][0]['s3']['bucket']['name']
        key = event['Records'][0]['s3']['object']['key']
        
        logger.info(f"Processing file: {key} from bucket: {bucket}")

        # Read the image from S3
        response = s3_client.get_object(Bucket=bucket, Key=key)
        image_data = response['Body'].read()

        # Process the image (placeholder for actual image processing logic)
        processed_image_data = image_data  # Replace with actual processing

        # Write results back to S3
        output_key = f"processed/{key}"
        s3_client.put_object(Bucket=bucket, Key=output_key, Body=processed_image_data)
        logger.info(f"Processed image saved to: {output_key}")

        # Send notification via SNS
        sns_topic_arn = 'arn:aws:sns:REGION:ACCOUNT_ID:TOPIC_NAME'  # Replace with your SNS topic ARN
        sns_client.publish(
            TopicArn=sns_topic_arn,
            Message=json.dumps({'default': f'Image processed: {output_key}'}),
            MessageStructure='json'
        )
        logger.info(f"Notification sent for processed image: {output_key}")

    except Exception as e:
        logger.error(f"Error processing file {key} from bucket {bucket}: {str(e)}")
        raise e